export function getRuleForTask(task: Task): Rule | undefined {
  if (task.ruleId) return goldenRules.find(r => r.id === task.ruleId);
  const categoryRules = goldenRules.filter(r => r.category === task.category);
  return categoryRules.length > 0 ? categoryRules[0] : undefined;
}

export function getBuddyHint(ruleId: number, methodology?: Methodology): string {
  const method = methodology || USER_METHODOLOGY;
  const rule = goldenRules.find(r => r.id === ruleId);
  if (!rule) return "";
  return rule.hints[method] || rule.hints.default;
}

/** Форматирование подлежащего/сказуемого для ответа (остров предложений). */
function joinForDisplay(arr: string[]): string {
  if (arr.length === 0) return "";
  if (arr.length === 1) return arr[0];
  if (arr.length === 2) return `${arr[0]} и ${arr[1]}`;
  return arr.slice(0, -1).join(", ") + " и " + arr[arr.length - 1];
}

function formatSubjectPredicate(subject: string[], predicate: string[]): string {
  return `Подлежащее: «${joinForDisplay(subject)}», сказуемое: «${joinForDisplay(predicate)}»`;
}

/** Конвертация задания из sentences.ts в формат Task для офлайн-режима. */
function sentenceTaskToTask(s: SentenceTask, numericId: number): Task {
  const difficulty = s.difficulty === "базовый" ? 1 : 2;
  const rule = s.rule;
  const question =
    s.type === "find_subject_predicate"
      ? `Найди подлежащее и сказуемое: «${s.sentence}»`
      : s.type === "add_commas"
        ? `Расставь запятые: «${s.sentence}»`
        : `Расставь запятые и найди основу: «${s.sentence}»`;
  let correct: string;
  let options: string[];
  const ruleId = s.type === "find_subject_predicate" ? 4 : 12;
  if (s.type === "find_subject_predicate" && s.subject && s.predicate) {
    correct = formatSubjectPredicate(s.subject, s.predicate);
    const wrong = formatSubjectPredicate(s.predicate, s.subject);
    options = [correct, wrong];
  } else {
    correct = s.corrected ?? s.sentence;
    const wrong = s.sentence;
    options = correct !== wrong ? [correct, wrong] : [correct];
  }
  return {
    id: numericId,
    type: "syntax",
    word: s.sentence,
    question,
    correct,
    options,
    audio: rule,
    hint: rule,
    rule,
    ruleId,
    difficulty,
    category: "syntax",
  };
}

